@app.route('/admin/tokens', methods=['POST'])
def create_token():
    data = request.get_json()
    
    if not data or 'token' not in data or 'user_id' not in data or 'client_id' not in data or 'expires_at' not in data:
        return jsonify({'error': 'Missing required fields'}), 400
    
    db = get_db()
    try:
        db.execute(
            'INSERT INTO access_tokens (token, user_id, client_id, expires_at) VALUES (?, ?, ?, ?)',
            (data['token'], data['user_id'], data['client_id'], data['expires_at'])
        )
        db.commit()
        db.close()
        return jsonify({'message': 'Token created successfully'}), 201
    except sqlite3.IntegrityError:
        db.close()
        return jsonify({'error': 'Token already exists'}), 409

@app.route('/admin/tokens/<token>', methods=['DELETE'])
def delete_token(token):
    db = get_db()
    cursor = db.execute('DELETE FROM access_tokens WHERE token = ?', (token,))
    db.commit()
    
    if cursor.rowcount == 0:
        db.close()
        return jsonify({'error': 'Token not found'}), 404
    
    db.close()
    return jsonify({'message': 'Token deleted successfully'})

